package Full_Stack_ch3;

public class Evennumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int num=2;
        for(int i=1;i<=3;i++) {
            for(int j=1;j<=3;j++) {
                System.out.print(num + " ");
                num += 2;
            }
            System.out.println();
        }
	}

}
